1	export interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	export interface QuoteInput {
9	  items: Item[];
10	  yearsWithMHPCO?: number;
11	}
12	
13	export interface QuoteResult {
14	  premium: number;
15	}
16	
17	const PROCESSING_FEE = 5;
18	const DEFAULT_BASE_PREMIUM = 100;
19	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
20	  amulet: 60,
21	  staff: 80,
22	  potion: 40,
23	  rune: 25,
24	  moonstone: 25,
25	};
26	
27	const CURSE_SURCHARGE_RATE = 0.5;
28	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
29	
30	function basePremiumFor(item: Item): number {
31	  const base = BASE_PREMIUM_BY_TYPE[item.type] ?? DEFAULT_BASE_PREMIUM;
32	  const highEnchantmentSurcharge =
33	    item.enchantment === 5 ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
34	  const curseSurcharge = item.cursed ? CURSE_SURCHARGE_RATE : 0;
35	  return base * (1 + highEnchantmentSurcharge + curseSurcharge);
36	}
37	
38	const BLOCK_SIZE = 3;
39	const BLOCK_PREMIUM = 60;
40	
41	function groupByType(items: Item[]): Map<string, Item[]> {
42	  const groups = new Map<string, Item[]>();
43	  for (const item of items) {
44	    const group = groups.get(item.type) ?? [];
45	    group.push(item);
46	    groups.set(item.type, group);
47	  }
48	  return groups;
49	}
50	
51	function basePremiumForGroup(group: Item[]): number {
52	  if (group.length === BLOCK_SIZE) {
53	    return BLOCK_PREMIUM;
54	  }
55	  return group.reduce((sum, item) => sum + basePremiumFor(item), 0);
56	}
57	
58	export function quote(input: QuoteInput): QuoteResult {
59	  const groups = [...groupByType(input.items).values()];
60	  const basePremium = groups.reduce(
61	    (sum, group) => sum + basePremiumForGroup(group),
62	    0,
63	  );
64	
65	  const policyBase =
66	    input.yearsWithMHPCO !== undefined && input.yearsWithMHPCO >= 2
67	      ? basePremium * 0.8
68	      : basePremium;
69	
70	  return { premium: policyBase + PROCESSING_FEE };
71	}
