const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const LOYALTY_DISCOUNT_RATE = 0.2;
const LOYALTY_MIN_YEARS = 2;

function applyLoyaltyDiscount(
  basePremium: number,
  yearsWithMHPCO: number | undefined,
): number {
  const qualifies =
    yearsWithMHPCO !== undefined && yearsWithMHPCO >= LOYALTY_MIN_YEARS;
  return qualifies ? basePremium * (1 - LOYALTY_DISCOUNT_RATE) : basePremium;
}

